const sortCriteria = [{ label: '时间', sort: 'mr' },{ label: '阅读', sort: 'mv' },{ label: '喜爱', sort: 'tf'},{ label: '评分', sort: 'tr' }];
const Category = [["全部",""],["中文","/sub/chinese"],["日语","/sub/japanese"],["CG","/sub/CG"],["无码","/sub/no_mosaic"],["上色","/sub/coloring"]];
const weekDays = [{ "D": "周日", "N": "7" },{ "D": "周一", "N": "1" },{ "D": "周二", "N": "2" },{ "D": "周三", "N": "3" },{ "D": "周四", "N": "4" },{ "D": "周五", "N": "5" },{ "D": "周六", "N": "6" },{ "D": "完结", "N": "0" }];
const _list =[["同人","albums/doujin"],["韩漫","albums/hanman"],["English","albums/meiman"],["短篇","albums/short"],["单本","albums/single"]];
const typeList = [["日榜", "&t=t"],["周榜", "&t=w"],["月榜", "&t=m"],["总榜", ""]];
const sorts1 = ["無修正","劇情向","青年漫","校服","純愛","人妻","教師","百合","Yaoi","性轉","NTR","女裝","癡女","全彩","女性向","完結","純愛","禁漫漢化組"];
const sorts2 = ["御姐","熟女","未成年","巨乳","貧乳","女性支配","教師","女僕","護士","泳裝","眼鏡","連褲襪","其他制服","兔女郎"];
const sorts3 = ["群交","足交","束縛","肛交","阿黑顏","藥物","扶他","調教","野外露出","催眠","自慰","觸手","獸交","亞人","怪物女孩","皮物","附身","ryona","騎大車"];
const sorts4 = ["CG","重口","獵奇","非H","血腥暴力","站長推薦"];
const __list = [["其他","albums/another/sub/other"],["COS", "albums/another/sub/cosplay"],["3D", "albums/another/sub/3D"],["小说", "novels"]];

function put(data) {
    const { java, source, cookie } = this;
    return source.setVariable(JSON.stringify(data, null, '\t'));
}

function Get(e) {
    const { java, source, cookie } = this;
    var get = JSON.parse(source.getVariable());
    return get[e];
}

function checkLatency(urls, ctx) {
  const { java } = ctx;
  var results = [];
  var count = 0;
  for (var i = 0; i < urls.length; i++) {
    var url = urls[i].startsWith("http") ? urls[i] : "https://" + urls[i];
    try {
      java.toast(`\n检测可用线路：(${i + 1}/${urls.length})`);
      var start = Date.now();
      org.jsoup.Jsoup.connect(url)
        .method(org.jsoup.Connection.Method.HEAD)
        .timeout(10000)
        .ignoreHttpErrors(true)
        .execute();
      var end = Date.now();
      var latency = end - start;
      if (latency > 0) {
        count++;
        results.push({ host: url, latency: latency });
      }
    } catch (e) {
      java.log(`${url} 检测失败：${e.message}`);
    }
  }
  results.sort(function (a, b) {
    return a.latency - b.latency;
  });
  var availableUrls = results.map(item => item.host);
  java.longToast(`\n检测完成：共(${count}/${urls.length})个可用线路`);
  return availableUrls;
}

