        Log('【提示】\n暂无站点，无法切换');
        return $$$;
    }
    if (urlCount === 1) {
        Log('【提示】\n仅一个站点，无需切换\n（当前站点：' + $$$.urls[0] + '）');
        return $$$;
    }
    const currentFirst = $$$.urls[0];
